// AUTO-GENERATED BY scripts/stage-public.mjs — DO NOT EDIT BY HAND.
// Source of truth: scripts/<name>.mjs in the internal monorepo.
// Path references rewritten so the public repo can be self-contained.

import { readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { TRANSCRIPTION_TEXT, LINEAR_A_WORDS, LINEAR_A_FULL } from "../app/js/engine/data.mjs";
import { parseTranscription } from "../app/js/engine/parser.mjs";
import {
  fullNineLanguageComparison,
  singleLanguageMC,
  circularityBiasTest,
  signZeroTwoQeBinding,
  leavePdInspiredOut,
  reverseDirectionTest,
} from "../app/js/engine/comparison.mjs";
import { PRE_COMPUTED } from "../app/js/sections/comparison.mjs";
import { PRE_SIGN02, PRE_SIGN18_RJU, PRE_CIRCULARITY } from "../app/js/sections/sensitivity.mjs";

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(__dirname, "..");
const MC_TOL = 0.001;

const ITERATIONS = 100_000;
const MANIFEST_PATH = join(__dirname, "canonical-values.json");

function near(a, b, tol = MC_TOL) {
  return Math.abs(a - b) <= tol;
}

// Section literals are imported directly (no regex parsing of source files).
// Drift is therefore caught at the value level: rewording prose around the
// constants does not affect this gate. A schema sanity check still guards
// against accidental shape changes (e.g. dropping a field from PRE_COMPUTED).
function readSectionLiterals() {
  if (!Array.isArray(PRE_COMPUTED) || PRE_COMPUTED.length !== 9) {
    throw new Error(`PRE_COMPUTED: expected 9 entries, got ${PRE_COMPUTED?.length ?? "non-array"}`);
  }
  for (const e of PRE_COMPUTED) {
    for (const f of ["id", "pValue", "overlap", "fwPValue", "holmP"]) {
      if (e[f] === undefined) throw new Error(`PRE_COMPUTED entry missing field "${f}"`);
    }
  }
  return {
    fileEntries: PRE_COMPUTED.map(e => ({
      id: e.id, pValue: e.pValue, overlap: e.overlap, fwPValue: e.fwPValue, holmP: e.holmP,
    })),
    fileSens: {
      detP: PRE_SIGN02.det.pValue,
      phonP: PRE_SIGN02.phon.pValue,
      sign18rjuP: PRE_SIGN18_RJU.pValue,
      realOverlap: PRE_CIRCULARITY.realOverlap,
      uniformP: PRE_CIRCULARITY.uniformP,
      freqWeightedP: PRE_CIRCULARITY.freqWeightedP,
      spearmanRho: PRE_CIRCULARITY.spearmanRho,
      tierSweep: (PRE_CIRCULARITY.tierSweep ?? []).map(s => ({
        tierCount: s.tierCount, freqWeightedP: s.freqWeightedP,
      })),
    },
  };
}

// overview.mjs key-finding strings remain prose-embedded literals (rewriting
// them as template substitutions would be a much larger UI change). The five
// extracted numbers are 3-decimal rounded forms of manifest values, so any
// drift here is also caught by verify-prose against canonical-values.json.
function extractOverviewLiterals(text) {
  const patterns = [
    { id: "minoan.pValue",          re: /MC p = (\d+\.\d+) under default/ },
    { id: "minoan.holmP",           re: /Holm p = (\d+\.\d+)/ },
    { id: "minoan.fwPValue",        re: /FW p = (\d+\.\d+)/ },
    { id: "leavePD.filtered.pValue", re: /filtered MC p = (\d+\.\d+)/ },
    { id: "sign02.phon.pValue",     re: /phonetic treatment of sign 02 \(MC p = (\d+\.\d+)\)/ },
  ];
  const out = {};
  const missing = [];
  for (const { id, re } of patterns) {
    const m = text.match(re);
    if (!m) { missing.push(id); continue; }
    out[id] = Number(m[1]);
  }
  if (missing.length > 0) {
    throw new Error(`overview.mjs: could not find canonical literal(s): ${missing.join(", ")}`);
  }
  return out;
}

function main() {
  console.log(`verify-canonical: ${ITERATIONS.toLocaleString()} iterations per MC run\n`);

  const { fileEntries, fileSens } = readSectionLiterals();

  const [sideA, sideB] = parseTranscription(TRANSCRIPTION_TEXT);

  const comp = fullNineLanguageComparison(sideA, sideB, { iterations: ITERATIONS });
  const det = singleLanguageMC(sideA, sideB, LINEAR_A_WORDS, { iterations: ITERATIONS, includeDet: false });
  const phon = singleLanguageMC(sideA, sideB, LINEAR_A_WORDS, {
    iterations: ITERATIONS,
    seed: 314160,
    includeDet: true,
    valueOverrides: new Map([[2, "i"]]),
  });
  const sign18rju = singleLanguageMC(sideA, sideB, LINEAR_A_WORDS, {
    iterations: ITERATIONS,
    seed: 314161,
    valueOverrides: new Map([[18, "rju"]]),
  });
  const circ = circularityBiasTest(sideA, sideB, LINEAR_A_WORDS, { iterations: ITERATIONS });

  let failed = false;

  for (const expected of fileEntries) {
    const r = comp.results.find(x => x.id === expected.id);
    if (!r) {
      console.log(`FAIL  PRE_COMPUTED ${expected.id}: not found in computed results`);
      failed = true;
      continue;
    }
    const checks9 = [
      ["pValue", near(r.pValue, expected.pValue), r.pValue.toFixed(4), expected.pValue.toFixed(4), `tol ±${MC_TOL}`],
      ["overlap", r.overlap === expected.overlap, r.overlap, expected.overlap, "exact"],
      ["fwPValue", near(r.fwPValue, expected.fwPValue), r.fwPValue.toFixed(4), expected.fwPValue.toFixed(4), `tol ±${MC_TOL}`],
      ["holmP", near(r.holmP, expected.holmP), r.holmP.toFixed(4), expected.holmP.toFixed(4), `tol ±${MC_TOL}`],
    ];
    for (const [field, ok, computed, file, mode] of checks9) {
      if (!ok) failed = true;
      console.log(`${ok ? "PASS" : "FAIL"}  PRE_COMPUTED ${expected.id} ${field}: computed ${computed} vs file ${file} (${mode})`);
    }
  }

  const checks = [
    ["PRE_SIGN02.det pValue", det.pValue, fileSens.detP],
    ["PRE_SIGN02.phon pValue", phon.pValue, fileSens.phonP],
    ["PRE_SIGN18_RJU pValue", sign18rju.pValue, fileSens.sign18rjuP],
    ["PRE_CIRCULARITY uniformP", circ.uniformP, fileSens.uniformP],
    ["PRE_CIRCULARITY freqWeightedP", circ.freqWeightedP, fileSens.freqWeightedP],
  ];

  for (const [label, computed, expected] of checks) {
    const ok = near(computed, expected);
    if (!ok) failed = true;
    console.log(
      `${ok ? "PASS" : "FAIL"}  ${label}: computed ${Number(computed).toFixed(4)} vs file ${Number(expected).toFixed(4)} (tol ±${MC_TOL})`
    );
  }

  const rhoOk = near(circ.spearmanRho, fileSens.spearmanRho, MC_TOL);
  if (!rhoOk) failed = true;
  console.log(
    `${rhoOk ? "PASS" : "FAIL"}  PRE_CIRCULARITY spearmanRho: computed ${circ.spearmanRho.toFixed(3)} vs file ${fileSens.spearmanRho.toFixed(3)} (tol ±${MC_TOL})`
  );

  const overlapOk = circ.realOverlap === fileSens.realOverlap;
  if (!overlapOk) failed = true;
  console.log(
    `${overlapOk ? "PASS" : "FAIL"}  PRE_CIRCULARITY realOverlap: computed ${circ.realOverlap} vs file ${fileSens.realOverlap} (exact)`
  );

  // Sign 02 / qe binding (Extended Analysis #28).
  // Counts are exact integers from the transcription; exactP is an analytic
  // hypergeometric-SF value (pure deterministic, not Monte Carlo).
  const QE_EXPECTED = {
    s02InitialCount: 19,
    s02FollowedByS12: 13,
    s12FollowerCount: 17,
    totalFollowers: 180,
    exactP: 2.624632773127958e-12,
  };
  const qe = signZeroTwoQeBinding(sideA, sideB, { iterations: ITERATIONS });
  const qeIntChecks = [
    ["s02InitialCount", qe.s02InitialCount, QE_EXPECTED.s02InitialCount],
    ["s02FollowedByS12", qe.s02FollowedByS12, QE_EXPECTED.s02FollowedByS12],
    ["s12FollowerCount", qe.s12FollowerCount, QE_EXPECTED.s12FollowerCount],
    ["totalFollowers", qe.totalFollowers, QE_EXPECTED.totalFollowers],
  ];
  for (const [field, computed, expected] of qeIntChecks) {
    const ok = computed === expected;
    if (!ok) failed = true;
    console.log(`${ok ? "PASS" : "FAIL"}  PRE_QE_BINDING ${field}: computed ${computed} vs expected ${expected} (exact)`);
  }
  // exactP: relative tolerance 0.1% — analytic, but small floating-point drift
  // is acceptable across Node versions.
  const qePOk = Math.abs(qe.exactP - QE_EXPECTED.exactP) / QE_EXPECTED.exactP < 1e-3;
  if (!qePOk) failed = true;
  console.log(
    `${qePOk ? "PASS" : "FAIL"}  PRE_QE_BINDING exactP: computed ${qe.exactP.toExponential(3)} vs expected ${QE_EXPECTED.exactP.toExponential(3)} (rel tol 1e-3)`,
  );

  if (Array.isArray(fileSens.tierSweep) && fileSens.tierSweep.length > 0 && Array.isArray(circ.tierSweep)) {
    for (const expected of fileSens.tierSweep) {
      const c = circ.tierSweep.find(s => s.tierCount === expected.tierCount);
      if (!c) {
        console.log(`FAIL  PRE_CIRCULARITY tierSweep T=${expected.tierCount}: not produced by engine`);
        failed = true;
        continue;
      }
      const ok = near(c.freqWeightedP, expected.freqWeightedP, MC_TOL);
      if (!ok) failed = true;
      console.log(
        `${ok ? "PASS" : "FAIL"}  PRE_CIRCULARITY tierSweep T=${expected.tierCount} fwP: computed ${c.freqWeightedP.toFixed(4)} vs file ${expected.freqWeightedP.toFixed(4)} (tol ±${MC_TOL})`
      );
    }
  }

  // ---------------------------------------------------------------------
  // Manifest cross-check: scripts/canonical-values.json is the single
  // source of truth referenced by verify-prose and by every public-facing
  // document. The engine must reproduce every value in it. If the manifest
  // is missing or stale, regenerate via: node scripts/generate-canonical-values.mjs
  // ---------------------------------------------------------------------
  let manifest;
  try {
    manifest = JSON.parse(readFileSync(MANIFEST_PATH, "utf8"));
  } catch (err) {
    console.log(`\nFAIL  canonical-values.json: ${err.message}`);
    console.log("      Run: node scripts/generate-canonical-values.mjs");
    process.exit(1);
  }

  // Per-language: corpusSize, effectiveSize, hyperP (in addition to fields
  // already covered above via PRE_COMPUTED).
  for (const expected of manifest.comparison) {
    const r = comp.results.find(x => x.id === expected.id);
    if (!r) {
      console.log(`FAIL  manifest ${expected.id}: not found in computed results`);
      failed = true;
      continue;
    }
    const checks = [
      ["corpusSize",    r.corpusSize === expected.corpusSize,    r.corpusSize,    expected.corpusSize,    "exact"],
      ["effectiveSize", r.effectiveSize === expected.effectiveSize, r.effectiveSize, expected.effectiveSize, "exact"],
      ["hyperP",        near(r.hyperP, expected.hyperP),         r.hyperP.toFixed(4), expected.hyperP.toFixed(4), `tol ±${MC_TOL}`],
    ];
    for (const [field, ok, computed, file, mode] of checks) {
      if (!ok) failed = true;
      console.log(`${ok ? "PASS" : "FAIL"}  manifest ${expected.id} ${field}: computed ${computed} vs manifest ${file} (${mode})`);
    }
  }

  // Leave-PD-inspired-out ablation (full vs filtered).
  const leavePD = leavePdInspiredOut(sideA, sideB, { iterations: ITERATIONS });
  const leaveChecks = [
    ["leavePD.full.overlap",        leavePD.full.overlap === manifest.leavePD.full.overlap,            leavePD.full.overlap,        manifest.leavePD.full.overlap,        "exact"],
    ["leavePD.full.pValue",         near(leavePD.full.pValue, manifest.leavePD.full.pValue),           leavePD.full.pValue.toFixed(4),     manifest.leavePD.full.pValue.toFixed(4),     `tol ±${MC_TOL}`],
    ["leavePD.full.corpusSize",     leavePD.full.corpusSize === manifest.leavePD.full.corpusSize,     leavePD.full.corpusSize,     manifest.leavePD.full.corpusSize,     "exact"],
    ["leavePD.filtered.overlap",    leavePD.filtered.overlap === manifest.leavePD.filtered.overlap,    leavePD.filtered.overlap,    manifest.leavePD.filtered.overlap,    "exact"],
    ["leavePD.filtered.pValue",     near(leavePD.filtered.pValue, manifest.leavePD.filtered.pValue),   leavePD.filtered.pValue.toFixed(4), manifest.leavePD.filtered.pValue.toFixed(4), `tol ±${MC_TOL}`],
    ["leavePD.filtered.corpusSize", leavePD.filtered.corpusSize === manifest.leavePD.filtered.corpusSize, leavePD.filtered.corpusSize, manifest.leavePD.filtered.corpusSize, "exact"],
    ["leavePD.droppedCount",        leavePD.droppedCount === manifest.leavePD.droppedCount,            leavePD.droppedCount,        manifest.leavePD.droppedCount,        "exact"],
  ];
  for (const [field, ok, computed, file, mode] of leaveChecks) {
    if (!ok) failed = true;
    console.log(`${ok ? "PASS" : "FAIL"}  manifest ${field}: computed ${computed} vs manifest ${file} (${mode})`);
  }

  // Full corpus (49-word LA, including LINEAR_A_EXCLUDED).
  const fullCorpus = singleLanguageMC(sideA, sideB, LINEAR_A_FULL, { iterations: ITERATIONS });
  const fullCorpusChecks = [
    ["fullCorpus.overlap",    fullCorpus.overlap === manifest.fullCorpus.overlap,        fullCorpus.overlap,    manifest.fullCorpus.overlap,    "exact"],
    ["fullCorpus.pValue",     near(fullCorpus.pValue, manifest.fullCorpus.pValue),       fullCorpus.pValue.toFixed(4), manifest.fullCorpus.pValue.toFixed(4), `tol ±${MC_TOL}`],
    ["fullCorpus.corpusSize", LINEAR_A_FULL.length === manifest.fullCorpus.corpusSize,  LINEAR_A_FULL.length, manifest.fullCorpus.corpusSize, "exact"],
  ];
  for (const [field, ok, computed, file, mode] of fullCorpusChecks) {
    if (!ok) failed = true;
    console.log(`${ok ? "PASS" : "FAIL"}  manifest ${field}: computed ${computed} vs manifest ${file} (${mode})`);
  }

  // Direction-reversal test (Sign 02 stripped, reading reversed).
  const reversal = reverseDirectionTest(sideA, sideB, LINEAR_A_WORDS, { iterations: ITERATIONS });
  const reversalChecks = [
    ["reversal.forwardOverlap",  reversal.forward.overlap === manifest.reversal.forwardOverlap,   reversal.forward.overlap,    manifest.reversal.forwardOverlap, "exact"],
    ["reversal.forwardP",        near(reversal.forward.pValue, manifest.reversal.forwardP),       reversal.forward.pValue.toFixed(4),  manifest.reversal.forwardP.toFixed(4), `tol ±${MC_TOL}`],
    ["reversal.reversedOverlap", reversal.reversed.overlap === manifest.reversal.reversedOverlap, reversal.reversed.overlap,   manifest.reversal.reversedOverlap, "exact"],
    ["reversal.reversedP",       near(reversal.reversed.pValue, manifest.reversal.reversedP),     reversal.reversed.pValue.toFixed(4), manifest.reversal.reversedP.toFixed(4), `tol ±${MC_TOL}`],
  ];
  for (const [field, ok, computed, file, mode] of reversalChecks) {
    if (!ok) failed = true;
    console.log(`${ok ? "PASS" : "FAIL"}  manifest ${field}: computed ${computed} vs manifest ${file} (${mode})`);
  }

  // Iteration count and tolerance must agree. If someone bumps ITERATIONS
  // here without regenerating the manifest, we want a loud failure.
  const iterOk = manifest.iterations === ITERATIONS;
  if (!iterOk) failed = true;
  console.log(`${iterOk ? "PASS" : "FAIL"}  manifest.iterations: script ${ITERATIONS} vs manifest ${manifest.iterations} (exact)`);

  // overview.mjs key-finding literals: lock the 3-decimal rounded forms
  // of the Minoan MC/Holm/FW values, the leave-PD-inspired-out filtered
  // p, and the Sign 02 phonetic p against the manifest. The file has
  // hardcoded canonical literals separate from PRE_COMPUTED, so drift
  // there is not caught by the PRE_COMPUTED comparison.
  const overviewText = readFileSync(join(REPO_ROOT, "app/js/sections/overview.mjs"), "utf8");
  let overview;
  try {
    overview = extractOverviewLiterals(overviewText);
  } catch (err) {
    console.log(`FAIL  overview.mjs: ${err.message}`);
    failed = true;
  }
  if (overview) {
    const minoan = manifest.comparison.find(r => r.id === "minoan");
    const overviewChecks = [
      ["minoan.pValue",           overview["minoan.pValue"],          Number(minoan.pValue.toFixed(3))],
      ["minoan.holmP",            overview["minoan.holmP"],           Number(minoan.holmP.toFixed(3))],
      ["minoan.fwPValue",         overview["minoan.fwPValue"],        Number(minoan.fwPValue.toFixed(3))],
      ["leavePD.filtered.pValue", overview["leavePD.filtered.pValue"], Number(manifest.leavePD.filtered.pValue.toFixed(3))],
      ["sign02.phon.pValue",      overview["sign02.phon.pValue"],     Number(manifest.sign02.phon.pValue.toFixed(3))],
    ];
    for (const [field, file, manifestRounded] of overviewChecks) {
      const ok = file === manifestRounded;
      if (!ok) failed = true;
      console.log(
        `${ok ? "PASS" : "FAIL"}  overview.mjs ${field}: file ${file.toFixed(3)} vs manifest@3dp ${manifestRounded.toFixed(3)} (exact)`
      );
    }
  }

  console.log(failed ? "\nverify-canonical: FAILED" : "\nverify-canonical: all checks passed");
  process.exit(failed ? 1 : 0);
}

main();
